const inputData = $input.first()?.json?.body || $input.first()?.json || {};

// Extract variables from prior nodes or the webhook payload
const chat_id = inputData.chat_id;
const text = inputData.text;
const username = inputData.username || "User";

// Validation Sandwich PRE: Check required fields
if (!chat_id || !text) {
  return [{
    json: {
      isValid: false,
      error_code: "VALIDATION_ERROR",
      error_message: "Missing required fields 'chat_id' or 'text'"
    }
  }];
}

// Pass validated data forward
return [{
  json: {
    isValid: true,
    chat_id: chat_id,
    text: text,
    username: username
  }
}];

const ai_response = $input.first()?.json?.text || $input.first()?.json?.output || $input.first()?.json?.response || "";
// Bring forward chat_id from the IF node
const chat_id = $node["Is Valid?"].json.chat_id;

// POST validation: ensure the AI actually responded
if (!ai_response) {
  return [{
    json: {
      success: false,
      error_code: "AI_GENERATION_FAILED",
      error_message: "AI failed to return an output",
      data: null,
      _meta: {
        source: "NN_03_AI_Agent",
        timestamp: new Date().toISOString(),
        workflow_id: "",
        version: "1.0.0"
      }
    }
  }];
}

return [{
  json: {
    success: true,
    error_code: null,
    error_message: null,
    data: {
      chat_id: chat_id,
      ai_response: ai_response
    },
    _meta: {
      source: "NN_03_AI_Agent",
      timestamp: new Date().toISOString(),
      workflow_id: "",
      version: "1.0.0"
    }
  }
}];

const errorInfo = $input.first()?.json;

return [{
  json: {
    success: false,
    error_code: errorInfo?.error_code || "REJECTED_VALIDATION",
    error_message: errorInfo?.error_message || "Validation failed in AI Agent flow",
    data: null,
    _meta: {
      source: "NN_03_AI_Agent",
      timestamp: new Date().toISOString(),
      workflow_id: "",
      version: "1.0.0"
    }
  }
}];

const executionError = $input.first()?.json?.execution?.error || {};
const errorMessage = executionError.message || "Unknown execution error";

return [{
  json: {
    success: false,
    error_code: "EXECUTION_ERROR",
    error_message: errorMessage,
    data: null,
    _meta: {
      source: "NN_03_AI_Agent",
      timestamp: new Date().toISOString(),
      workflow_id: "",
      version: "1.0.0"
    }
  }
}];
